export function seedMojLawCards(db: Database.Database): void {
  const stmt = db.prepare(`
    INSERT OR REPLACE INTO law_cards
      (card_id, law_name, article, summary, content, category, search_keywords, is_active)
    VALUES
      (@cardId, @lawName, @article, @summary, @content, @category, @searchKeywords, @isActive)
  `);
  const run = db.transaction((cards: LawCardSeed[]) => {
    for (const c of cards) {
      stmt.run({
        cardId: c.cardId,
        lawName: c.lawName,
        article: c.article ?? null,
        summary: c.summary ?? null,
        content: c.content,
        category: c.category ?? null,
        searchKeywords: c.searchKeywords ?? null,
        isActive: c.isActive ?? 1,
      });
    }
  });
  run(mojLawCards);

  // Deactivate old simplified cards for laws now covered comprehensively by MOJ data
  const coveredLaws = [...new Set(mojLawCards.map(c => c.lawName))];
  const deactivate = db.prepare(
    'UPDATE law_cards SET is_active = 0 WHERE law_name = ? AND card_id < 2000'
  );
  const deactivateAll = db.transaction(() => {
    for (const law of coveredLaws) deactivate.run(law);
  });
  deactivateAll();
}